const D2_YONSEI_LESS_1_WEEK: ItemSeed[] = [
  {
    id: "d2-ys-lt1-io",
    text: "Visit International Office",
    detail: "Underwood Hall, 1st floor",
  },
  {
    id: "d2-ys-lt1-sim",
