"use client";

import { useRouter } from "next/navigation";
import { useEffect, useMemo, useState } from "react";
import { ProgressBar } from "@/components/ProgressBar";
import { QuestionCard } from "@/components/QuestionCard";
import type {
  ArrivalTime,
  Scholarship,
  University,
  UserProfile,
  VisaType,
} from "@/types";
import { PROFILE_STORAGE_KEY } from "@/types";

type StepKey = "visa" | "university" | "arrival" | "scholarship";

const TOTAL_STEPS = 4;

function needsUniversity(visa: VisaType | undefined) {
  return visa === "D-2" || visa === "D-4";
}

function saveProfile(p: UserProfile) {
  if (typeof window === "undefined") return;
  localStorage.setItem(PROFILE_STORAGE_KEY, JSON.stringify(p));
}

export default function OnboardingPage() {
  const router = useRouter();
  const [stepIndex, setStepIndex] = useState(0); // 0..3 maps to 4 steps
  const [profile, setProfile] = useState<Partial<UserProfile>>({});

  const steps: StepKey[] = useMemo(
    () => ["visa", "university", "arrival", "scholarship"],
    []
  );

  const currentKey = steps[stepIndex];

  useEffect(() => {
    if (currentKey !== "university") return;
    if (!needsUniversity(profile.visaType)) {
      setProfile((p) => ({ ...p, university: null }));
      setStepIndex((i) => Math.min(i + 1, TOTAL_STEPS - 1));
    }
  }, [currentKey, profile.visaType]);

  function goNext() {
    setStepIndex((i) => Math.min(i + 1, TOTAL_STEPS - 1));
  }

  function finish(scholarship: Scholarship) {
