"use client";

import Link from "next/link";
import { useEffect, useMemo, useState } from "react";
import { ChecklistItem } from "@/components/ChecklistItem";
import { UniversityBadge } from "@/components/UniversityBadge";
import { generateChecklist } from "@/lib/checklists";
import type { ChecklistItem as ChecklistItemType, UserProfile } from "@/types";
import {
  CHECKLIST_STORAGE_KEY,
  PROFILE_STORAGE_KEY,
} from "@/types";

function loadProfile(): UserProfile | null {
  if (typeof window === "undefined") return null;
  const raw = localStorage.getItem(PROFILE_STORAGE_KEY);
  if (!raw) return null;
  try {
    return JSON.parse(raw) as UserProfile;
  } catch {
    return null;
  }
}

function loadCompleted(): Record<string, boolean> {
  if (typeof window === "undefined") return {};
  const raw = localStorage.getItem(CHECKLIST_STORAGE_KEY);
  if (!raw) return {};
  try {
    return JSON.parse(raw) as Record<string, boolean>;
  } catch {
    return {};
  }
}

function saveCompleted(map: Record<string, boolean>) {
  localStorage.setItem(CHECKLIST_STORAGE_KEY, JSON.stringify(map));
}

export default function ChecklistPage() {
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [items, setItems] = useState<ChecklistItemType[]>([]);
  const [completedMap, setCompletedMap] = useState<Record<string, boolean>>({});

  useEffect(() => {
    const p = loadProfile();
    if (!p) return;
    setProfile(p);
    const generated = generateChecklist(p);
    const saved = loadCompleted();
    setCompletedMap(saved);
    setItems(
      generated.map((it) => ({
        ...it,
        completed: Boolean(saved[it.id]),
      }))
    );
  }, []);

  const completedCount = useMemo(
    () => items.filter((i) => i.completed).length,
    [items]
  );

  function handleToggle(id: string, completed: boolean) {
    setItems((prev) =>
      prev.map((it) => (it.id === id ? { ...it, completed } : it))
    );
    setCompletedMap((prev) => {
      const next = { ...prev, [id]: completed };
      saveCompleted(next);
      return next;
    });
  }

  if (!profile) {
    return (
      <main className="page-enter flex min-h-dvh flex-col items-center justify-center bg-surface px-6 text-center">
        <p className="text-sm text-muted">No profile found.</p>
        <Link
          href="/onboarding"
          className="mt-4 rounded-btn bg-primary px-5 py-3 text-sm font-semibold text-white"
        >
          Start onboarding
        </Link>
      </main>
    );
  }

  return (
    <main className="page-enter min-h-dvh bg-surface px-5 pb-28 pt-8 safe-bottom">
      <header className="mb-6">
        {profile.university ? (
          <div className="mb-4 flex flex-wrap items-center gap-2">
            <span className="text-sm font-semibold text-muted">[</span>
            <UniversityBadge university={profile.university} />
            <span className="text-sm font-semibold text-muted">]</span>
          </div>
        ) : null}
        <h1 className="text-2xl font-bold text-ink">Your checklist</h1>
        <p className="mt-2 text-sm text-muted">
          Tailored to your visa, timing, and school.
        </p>
      </header>

      <p className="mb-4 text-sm font-semibold text-primary">
        {completedCount} of {items.length || "—"} steps completed ✓
      </p>

      <div className="space-y-3">
        {items.map((it) => (
          <ChecklistItem key={it.id} item={it} onToggle={handleToggle} />
        ))}
      </div>

      <div className="pointer-events-none fixed bottom-0 left-1/2 z-10 w-full max-w-mobile -translate-x-1/2 bg-gradient-to-t from-surface via-surface to-transparent px-5 pb-6 pt-10 safe-bottom">
        <div className="pointer-events-auto">
          <Link
            href="/chat"
            className="flex w-full items-center justify-center gap-2 rounded-btn bg-primary px-5 py-4 text-center text-base font-semibold text-white shadow-lg shadow-primary/25 transition hover:bg-primary-dark"
          >
            Ask AI Assistant
            <span aria-hidden>→</span>
          </Link>
        </div>
      </div>
    </main>
  );
}

