function parseDataUrl(dataUrl: string): { mediaType: string; data: string } | null {
  const match = /^data:([^;]+);base64,(.+)$/i.exec(dataUrl.trim());
  if (!match) return null;
  return { mediaType: match[1], data: match[2] };
}

function toAnthropicMessages(messages: Message[]): Anthropic.MessageParam[] {
  return messages
    .filter((m) => m.content.trim().length > 0 || m.imageUrl)
    .map((m) => {
      if (m.role === "assistant") {
        return { role: "assistant" as const, content: m.content };
      }
      if (m.imageUrl) {
        const parsed = parseDataUrl(m.imageUrl);
        if (parsed) {
          const media =
            parsed.mediaType === "image/jpg" ? "image/jpeg" : parsed.mediaType;
          return {
            role: "user" as const,
            content: [
              {
                type: "image" as const,
                source: {
                  type: "base64" as const,
                  media_type: media as
                    | "image/jpeg"
                    | "image/png"
                    | "image/gif"
                    | "image/webp",
                  data: parsed.data,
                },
              },
              { type: "text" as const, text: m.content || "See image." },
            ],
          };
        }
      }
      return { role: "user" as const, content: m.content };
    });
}

export async function POST(req: Request) {
  try {
    const body = (await req.json()) as {
      messages?: Message[];
      userProfile?: UserProfile;
    };

    if (!body.messages?.length || !body.userProfile) {
      return NextResponse.json(
        { error: "messages and userProfile are required" },
        { status: 400 }
      );
    }

    getAnthropicClient(); // validate key early

    const system = buildSystemPrompt(body.userProfile);
    const anthropicMessages = toAnthropicMessages(body.messages);

    const anthropic = getAnthropicClient();
    const res = await anthropic.messages.create({
      model: CLAUDE_MODEL,
      max_tokens: 900,
      system,
      messages: anthropicMessages,
    });

    const text = res.content
      .filter((b) => b.type === "text")
      .map((b) => (b as { text: string }).text)
      .join("\n")
      .trim();

    return NextResponse.json({ text });
  } catch (err) {
    const message = err instanceof Error ? err.message : "Unknown error";
    return NextResponse.json({ error: message }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { CLAUDE_MODEL, getAnthropicClient } from "@/lib/claude";

function normalizeBase64(input: string): { mediaType: string; data: string } {
  const trimmed = input.trim();
  const dataUrl = /^data:([^;]+);base64,(.+)$/i.exec(trimmed);
  if (dataUrl) {
    const media =
      dataUrl[1] === "image/jpg" ? "image/jpeg" : dataUrl[1];
    return { mediaType: media, data: dataUrl[2] };
  }
  return { mediaType: "image/jpeg", data: trimmed };
}

export async function POST(req: Request) {
  try {
    const body = (await req.json()) as {
      imageBase64?: string;
      language?: string;
    };

    if (!body.imageBase64) {
      return NextResponse.json(
        { error: "imageBase64 is required" },
        { status: 400 }
      );
    }

    const language = body.language?.trim() || "English";

    const { mediaType, data } = normalizeBase64(body.imageBase64);

    const system = `The user sent a photo of a Korean document.

Identify the document and respond with:
📄 This is a [document name in English and Korean]
💡 What it means: [simple explanation]
✅ What to do: [numbered steps]
📍 Where to go: [exact location or website]
⏰ Deadline: [if urgent, add ⚠️]

Documents to recognize:
- 전기요금 고지서 = electricity bill 
  → pay at GS25/CU convenience store or ATM
- 가스요금 고지서 = gas bill
  → pay at convenience store
- 건강보험료 고지서 = NHIS health insurance
  → ⚠️ affects visa renewal! pay at nhis.or.kr
- 계약서 = rental contract
  → register at 주민센터 within 14 days!
- 영수증 = receipt
- 세금 = tax document → visit local tax office
- 은행 = bank document

Always respond in ${language}.
Keep response under 200 words.`;

    const anthropic = getAnthropicClient();
    const res = await anthropic.messages.create({
      model: CLAUDE_MODEL,
      max_tokens: 900,
      system,
      messages: [
        {
          role: "user",
          content: [
            {
              type: "image",
              source: {
                type: "base64",
                media_type: mediaType as
                  | "image/jpeg"
                  | "image/png"
                  | "image/gif"
                  | "image/webp",
                data,
              },
            },
            {
              type: "text",
              text: "Analyze this document image and follow the output format.",
            },
          ],
        },
      ],
    });

    const text = res.content
      .filter((b) => b.type === "text")
      .map((b) => (b as { text: string }).text)
      .join("\n")
      .trim();

    return NextResponse.json({ text });
  } catch (err) {
    const message = err instanceof Error ? err.message : "Unknown error";
    return NextResponse.json({ error: message }, { status: 500 });
  }
}

