import type { FreshnessRecord, FreshnessStore } from "@/types";
import { ALL_TRACKED_CHECKLIST_ITEM_IDS } from "@/lib/checklists";
import { TRACKED_CAMPUS_RESOURCE_IDS } from "@/lib/campus-resources";

export const FRESHNESS_STORE_KEY = "freshness_store";
export const FRESHNESS_INITIALIZED_KEY = "freshness_initialized";

function nowIso(): string {
  return new Date().toISOString();
}

export function getFreshnessStore(): FreshnessStore {
  if (typeof window === "undefined") {
    return { records: {}, lastUpdated: nowIso() };
  }
  try {
    const raw = localStorage.getItem(FRESHNESS_STORE_KEY);
    if (!raw) {
      return { records: {}, lastUpdated: nowIso() };
    }
    const parsed = JSON.parse(raw) as FreshnessStore;
    if (!parsed.records || typeof parsed.records !== "object") {
      return { records: {}, lastUpdated: nowIso() };
    }
    return {
      records: parsed.records,
      lastUpdated: parsed.lastUpdated ?? nowIso(),
    };
  } catch {
    return { records: {}, lastUpdated: nowIso() };
  }
}

function writeStore(store: FreshnessStore): void {
  localStorage.setItem(FRESHNESS_STORE_KEY, JSON.stringify(store));
}

/** Seed all known checklist + campus IDs once so nothing shows stale on first launch */
export function ensureFreshnessInitialized(): void {
  if (typeof window === "undefined") return;
  if (localStorage.getItem(FRESHNESS_INITIALIZED_KEY)) return;

  const today = nowIso();
  const ids = [
    ...ALL_TRACKED_CHECKLIST_ITEM_IDS,
    ...TRACKED_CAMPUS_RESOURCE_IDS,
  ];
  const records: Record<string, FreshnessRecord> = {};
  for (const id of ids) {
    records[id] = {
      itemId: id,
      lastVerified: today,
      verifiedCount: 0,
      reportedOutdated: false,
    };
  }
  writeStore({ records, lastUpdated: today });
  localStorage.setItem(FRESHNESS_INITIALIZED_KEY, "1");
}

export function getFreshness(itemId: string): FreshnessRecord | null {
  if (typeof window === "undefined") return null;
  ensureFreshnessInitialized();
  const store = getFreshnessStore();
  return store.records[itemId] ?? null;
}

export function saveFreshness(record: FreshnessRecord): void {
  if (typeof window === "undefined") return;
  ensureFreshnessInitialized();
  const store = getFreshnessStore();
  store.records[record.itemId] = record;
  store.lastUpdated = nowIso();
  writeStore(store);
}

export function markVerified(itemId: string): void {
  if (typeof window === "undefined") return;
  ensureFreshnessInitialized();
  const existing = getFreshness(itemId);
  const today = nowIso();
  const next: FreshnessRecord = existing
    ? {
        ...existing,
        lastVerified: today,
        verifiedCount: existing.verifiedCount + 1,
        reportedOutdated: false,
        reportNote: undefined,
      }
    : {
        itemId,
        lastVerified: today,
        verifiedCount: 1,
        reportedOutdated: false,
      };
  saveFreshness(next);
}

export function reportOutdated(itemId: string, note: string): void {
  if (typeof window === "undefined") return;
  ensureFreshnessInitialized();
  const existing = getFreshness(itemId);
  const base: FreshnessRecord =
    existing ?? {
      itemId,
      lastVerified: nowIso(),
      verifiedCount: 0,
      reportedOutdated: false,
    };
  saveFreshness({
    ...base,
    reportedOutdated: true,
    reportNote: note.trim() || undefined,
  });
}

/** Calendar days since lastVerified (UTC date boundaries). */
export function getDaysOld(isoDate: string): number {
  const then = new Date(isoDate);
  const now = new Date();
  if (Number.isNaN(then.getTime())) return 9999;
  const startThen = Date.UTC(
    then.getUTCFullYear(),
    then.getUTCMonth(),
    then.getUTCDate()
  );
  const startNow = Date.UTC(
    now.getUTCFullYear(),
    now.getUTCMonth(),
    now.getUTCDate()
  );
  return Math.max(0, Math.floor((startNow - startThen) / 86_400_000));
}

export function getFreshnessLabel(itemId: string): {
  label: string;
  color: string;
  emoji: string;
} {
  const record = getFreshness(itemId);
  const days =
    record === null ? 9999 : getDaysOld(record.lastVerified);

  if (days <= 14) {
    return {
      label: "Verified recently",
      color: "#1D9E75",
      emoji: "✅",
    };
  }
  if (days <= 30) {
    return {
      label: "Verified this month",
      color: "#D97706",
      emoji: "🟡",
    };
  }
  if (days <= 60) {
    return {
      label: "Verify if still accurate",
      color: "#D97706",
      emoji: "⚠️",
    };
  }
  return {
    label: "Needs verification",
    color: "#D85A30",
    emoji: "🔴",
  };
}

export function resetAllFreshnessToToday(): void {
  if (typeof window === "undefined") return;
  const store = getFreshnessStore();
  const today = nowIso();
  const nextRecords: Record<string, FreshnessRecord> = {};
  for (const id of Object.keys(store.records)) {
    nextRecords[id] = {
      itemId: id,
      lastVerified: today,
      verifiedCount: 0,
      reportedOutdated: false,
    };
  }
  writeStore({ records: nextRecords, lastUpdated: today });
}

export function getAdminFreshnessRows(): {
  itemId: string;
  record: FreshnessRecord;
  daysOld: number;
}[] {
  if (typeof window === "undefined") return [];
  ensureFreshnessInitialized();
  const store = getFreshnessStore();
  const rows = Object.values(store.records).map((record) => ({
    itemId: record.itemId,
    record,
    daysOld: getDaysOld(record.lastVerified),
  }));
  rows.sort((a, b) => b.daysOld - a.daysOld);
  return rows;
}

"use client";

import { useEffect, useMemo, useState } from "react";
import {
  getDaysOld,
  getFreshness,
  getFreshnessLabel,
} from "@/lib/freshness";

export function FreshnessBadge({
  itemId,
  onVerify,
  onReport,
}: {
  itemId: string;
  onVerify: () => void;
  onReport: (note: string) => void;
}) {
  const [tick, setTick] = useState(0);
  const [showReport, setShowReport] = useState(false);
  const [reportDraft, setReportDraft] = useState("");
  const [toast, setToast] = useState<string | null>(null);

  const record = useMemo(() => getFreshness(itemId), [itemId, tick]);
  const meta = useMemo(() => getFreshnessLabel(itemId), [itemId, tick]);
  const daysOld = record ? getDaysOld(record.lastVerified) : null;

  useEffect(() => {
    if (!toast) return;
    const t = setTimeout(() => setToast(null), 2000);
    return () => clearTimeout(t);
  }, [toast]);

  function bump() {
    setTick((n) => n + 1);
  }

  function handleVerify() {
    onVerify();
    bump();
    setToast("Thanks!");
    setShowReport(false);
  }

  function handleReportSubmit(e: React.FormEvent) {
    e.preventDefault();
    const note = reportDraft.trim();
    if (!note) return;
    onReport(note);
    bump();
    setReportDraft("");
    setShowReport(false);
    setToast("Thanks for reporting!");
  }

  const daysPhrase =
    daysOld === null
      ? "No date on file"
      : daysOld === 0
        ? "Today"
        : daysOld === 1
          ? "1 day ago"
          : `${daysOld} days ago`;

  return (
    <div className="mt-3 border-t border-border pt-3">
      <div className="flex flex-wrap items-center justify-between gap-2">
        <div className="min-w-0 flex-1 text-[11px] leading-snug">
          <span style={{ color: meta.color }} aria-hidden>
            {meta.emoji}{" "}
          </span>
          <span className="font-semibold" style={{ color: meta.color }}>
            {meta.label}
          </span>
          <span className="text-muted"> · {daysPhrase}</span>
        </div>
        <div className="flex shrink-0 flex-wrap items-center gap-1">
          <span className="hidden text-[11px] text-muted sm:inline">
            Still accurate?
          </span>
          <button
            type="button"
            onClick={handleVerify}
            className="rounded-lg border border-primary/25 bg-white px-2 py-1 text-[11px] font-semibold text-primary transition hover:bg-primary-light"
          >
            👍
          </button>
          <button
            type="button"
            onClick={() => setShowReport((v) => !v)}
            className="rounded-lg border border-warning/40 bg-white px-2 py-1 text-[11px] font-semibold text-warning transition hover:bg-warning/10"
          >
            ⚠️ Report
          </button>
        </div>
      </div>

      {showReport ? (
        <form
          onSubmit={handleReportSubmit}
          className="mt-2 rounded-lg border border-border bg-surface/80 p-2"
        >
          <label className="sr-only" htmlFor={`report-${itemId}`}>
            Describe the issue
          </label>
          <textarea
            id={`report-${itemId}`}
            value={reportDraft}
            onChange={(e) => setReportDraft(e.target.value)}
            placeholder="What looks outdated?"
            rows={2}
            className="w-full resize-none rounded-md border border-border bg-white px-2 py-1.5 text-[11px] text-ink outline-none ring-primary/20 placeholder:text-muted focus:ring-1"
          />
          <div className="mt-2 flex justify-end gap-2">
            <button
              type="button"
              onClick={() => setShowReport(false)}
              className="rounded-md px-2 py-1 text-[11px] font-medium text-muted hover:text-ink"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={!reportDraft.trim()}
              className="rounded-md bg-primary px-3 py-1 text-[11px] font-semibold text-white disabled:opacity-40"
            >
              Submit
            </button>
          </div>
        </form>
      ) : null}

      {toast ? (
        <div
          className="pointer-events-none fixed bottom-24 left-1/2 z-[100] max-w-[90vw] -translate-x-1/2 rounded-full bg-ink px-4 py-2 text-center text-[11px] font-medium text-white shadow-lg"
          role="status"
        >
          {toast}
        </div>
      ) : null}
    </div>
  );
}

